function generateSlideDeckHTML(fields, nexusName, deploymentDate) {
  const nodoColors = {
    'NSI': '#0066FF',
    'GDI': '#00AA55',
    'PGI': '#FF8833'
  };
  
  let slidesHTML = `
    <div id="slides-container" style="font-family:Inter,system-ui,sans-serif;background:#0F172A;color:#FFFFFF;min-height:100vh;display:flex;flex-direction:column;padding:40px 20px">
      <div style="flex:1;display:flex;flex-direction:column;justify-content:center;align-items:center;max-width:900px;margin:0 auto;width:100%">
        <div id="slides-wrapper" style="width:100%;position:relative">`;
  
  // Title slide
  slidesHTML += `<div class="slide" style="display:none"><div style="text-align:center;padding:60px 40px"><div style="font-size:48px;font-weight:800;margin-bottom:20px">${nexusName}</div><div style="font-size:24px;color:rgba(255,255,255,0.7);margin-bottom:40px">Schema Slides — ` + deploymentDate + `</div></div></div>`;
  
  // Field slides
  fields.forEach((f, i) => {
    const tier = f.nodo_tier || 'GDI';
    const color = nodoColors[tier];
    slidesHTML += `<div class="slide" style="display:none;padding:40px"><div style="font-size:32px;font-weight:700;margin-bottom:20px">${f.field_name || 'Field ' + (i+1)}</div><div style="color:rgba(255,255,255,0.7);font-size:14px">${f.description || 'Governed field'}</div></div>`;
  });
  
  slidesHTML += `</div><div style="display:flex;justify-content:space-between;align-items:center;margin-top:40px;width:100%;max-width:900px"><button onclick="prevSlide()" style="padding:10px 16px;background:#FF8833;color:#FFFFFF;border:none;border-radius:6px;cursor:pointer">← Prev</button><div id="slide-counter" style="font-size:14px;color:rgba(255,255,255,0.6)">1 / ${fields.length + 1}</div><button onclick="nextSlide()" style="padding:10px 16px;background:#FF8833;color:#FFFFFF;border:none;border-radius:6px;cursor:pointer">Next →</button></div></div></div>
    <script>
      let currentSlide = 0;
      const slides = document.querySelectorAll('.slide');
      function showSlide(n) { slides.forEach(s => s.style.display = 'none'); if(slides[n]) slides[n].style.display = 'block'; document.getElementById('slide-counter').innerText = (n + 1) + ' / ' + slides.length; }
      function nextSlide() { currentSlide = (currentSlide + 1) % slides.length; showSlide(currentSlide); }
      function prevSlide() { currentSlide = (currentSlide - 1 + slides.length) % slides.length; showSlide(currentSlide); }
      showSlide(0);
      document.addEventListener('keydown', (e) => { if(e.key === 'ArrowRight') nextSlide(); if(e.key === 'ArrowLeft') prevSlide(); });
    </script>`;
  
  return slidesHTML;
}


