app.post('/api/documents/extract', async (req, res) => {
  const { content, document_type, record_id } = req.body;
  if (!content || content.trim().length < 10) return res.json({ success: false, error: 'No document content provided' });
  
  const startTime = Date.now();
  try {
    const extractRes = await axios.post('https://api.anthropic.com/v1/messages', {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 800,
      system: 'You are a governed document extraction engine. Read the document content and extract: (1) Key findings or data points, (2) Action items, (3) Compliance-relevant information, (4) A brief 2-3 sentence summary. Format as plain text with clear sections. Be concise.',
      messages: [{ role: 'user', content: 'Extract governed insights from this document:\n\n' + content.substring(0, 4000) }]
    }, {
      headers: { 'x-api-key': process.env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'Content-Type': 'application/json' }
    });
    
    const extracted = extractRes.data.content.map(c => c.text || '').join('').trim();
    const tokensIn = extractRes.data.usage ? extractRes.data.usage.input_tokens : 0;
    const tokensOut = extractRes.data.usage ? extractRes.data.usage.output_tokens : 0;
    const duration = Date.now() - startTime;
    
    // Store document with extracted text
    const result = await pool.query('INSERT INTO documents (record_id, document_type, document_source, extracted_text, igm_governed, chain_status) VALUES ($1,$2,$3,$4,true,$5) RETURNING *',
      [record_id || null, document_type || 'Uploaded Document', 'Direct Upload', extracted, 'extracted']);
    
    // Audit log
    try { await pool.query('INSERT INTO audit_log (table_name, action_type, changed_by, new_value) VALUES ($1,$2,$3,$4)',
      [TABLE_NAME, 'DOCUMENT_EXTRACT', 'AIRS Document AI', JSON.stringify({tokens_in: tokensIn, tokens_out: tokensOut, duration_ms: duration, doc_id: result.rows[0].id})]); } catch(e){}
    
    res.json({ success: true, document: result.rows[0], extracted: extracted, receipt: { tokens_in: tokensIn, tokens_out: tokensOut, duration_ms: duration, governed: true }});
  } catch (err) {
    res.json({ success: false, error: err.message });
  }
});


// --- Document Upload with AI Extraction ---
app.post('/api/documents/upload', upload ? upload.single('file') : function(req,res,next){next();}, async (req, res) => {
  if (!req.file) return res.json({ success: false, error: 'No file uploaded' });
  
  const startTime = Date.now();
  let textContent = '';
  const mime = req.file.mimetype;
  const name = req.file.originalname;
  
  try {
    // Extract text based on file type
    if (mime === 'application/pdf') {
      const pdfParse = require('pdf-parse');
      const data = await pdfParse(req.file.buffer);
      textContent = data.text;
    } else if (mime === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document') {
      const mammoth = require('mammoth');
      const result = await mammoth.extractRawText({ buffer: req.file.buffer });
      textContent = result.value;
    } else if (mime === 'text/plain' || mime === 'text/csv' || mime === 'text/html' || mime === 'text/markdown') {
      textContent = req.file.buffer.toString('utf8');
    } else {
      textContent = req.file.buffer.toString('utf8');
    }
    
    if (!textContent || textContent.trim().length < 5) {
      return res.json({ success: false, error: 'Could not extract text from file' });
    }
    
    // AI analysis of extracted content
    let aiSummary = textContent.substring(0, 500);
    if (process.env.ANTHROPIC_API_KEY) {
      try {
        const aiRes = await axios.post('https://api.anthropic.com/v1/messages', {
          model: 'claude-haiku-4-5-20251001',
          max_tokens: 600,
          system: 'Extract key findings, action items, compliance-relevant info, and a 2-3 sentence summary from this document. Be concise. Plain text only.',
          messages: [{ role: 'user', content: textContent.substring(0, 4000) }]
        }, {
          headers: { 'x-api-key': process.env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'Content-Type': 'application/json' }
        });
        aiSummary = aiRes.data.content.map(c => c.text || '').join('');
      } catch(aiErr) { aiSummary = 'AI extraction unavailable. Raw text: ' + textContent.substring(0, 500); }
    }
    
    const tokensIn = 0;
    const tokensOut = 0;
    const duration = Date.now() - startTime;
    
    // Store in database
    const result = await pool.query('INSERT INTO documents (document_type, document_source, extracted_text, igm_governed, chain_status) VALUES ($1,$2,$3,true,$4) RETURNING *',
      [req.body.document_type || name, 'File Upload: ' + name, aiSummary, 'extracted']);
    
    // Audit
    try { await pool.query('INSERT INTO audit_log (table_name, action_type, changed_by, new_value) VALUES ($1,$2,$3,$4)',
      [TABLE_NAME, 'DOCUMENT_UPLOAD', 'AIRS Document AI', JSON.stringify({file: name, size: req.file.size, duration_ms: duration, doc_id: result.rows[0].id})]); } catch(e){}
    
    res.json({ success: true, document: result.rows[0], extracted: aiSummary, filename: name, receipt: { duration_ms: duration, file_size: req.file.size, governed: true }});
  } catch (err) {
    res.json({ success: false, error: 'Failed to process file: ' + err.message });
  }
});



// GET /api/slides — Schema Slides from live data
app.get('/api/slides', async (req, res) => {
  try {
    // Get one record to show field values in action
    const result = await pool.query(`SELECT field_1, field_2, field_3, field_4, field_5, field_6, field_7, field_8, field_9, field_10, field_11, field_12 FROM ${TABLE_NAME} LIMIT 1`);
    const record = result.rows[0] || {};
    
    const fieldLabels = ['Field 1', 'Field 2', 'Field 3', 'Field 4', 'Field 5', 'Field 6', 'Field 7', 'Field 8', 'Field 9', 'Field 10', 'Field 11', 'Field 12'];
    const fieldKeys = ['field_1', 'field_2', 'field_3', 'field_4', 'field_5', 'field_6', 'field_7', 'field_8', 'field_9', 'field_10', 'field_11', 'field_12'];
    
    let html = `<div style="font-family:Inter,system-ui,sans-serif;background:#0F172A;color:white;min-height:100vh;display:flex;flex-direction:column;justify-content:center;align-items:center;padding:40px"><div style="max-width:800px;width:100%"><div id="slides">`;
    
    // Title slide
    html += `<div class="slide" style="text-align:center;padding:60px 40px"><h1 style="font-size:48px;font-weight:800;margin-bottom:30px">Schema Slides</h1><p style="font-size:24px;color:rgba(255,255,255,0.7)">12 Governed Fields in Action</p><p style="font-size:14px;color:rgba(255,255,255,0.5);margin-top:40px">Navigate with arrow keys or buttons</p></div>`;
    
    // Field slides with live data
    fieldKeys.forEach((key, i) => {
      const value = record[key] || '(empty)';
      html += `<div class="slide" style="display:none;padding:40px"><div style="font-size:14px;color:rgba(255,255,255,0.6);text-transform:uppercase;margin-bottom:20px">FIELD ${i+1} OF 12</div><h2 style="font-size:48px;font-weight:800;margin-bottom:30px">${fieldLabels[i]}</h2><div style="font-size:20px;color:rgba(255,255,255,0.8);line-height:1.6;margin-bottom:40px;background:rgba(0,0,0,0.3);padding:20px;border-radius:8px;border-left:3px solid #FF8A3C">Live Value:<br><strong>${String(value).substring(0, 200)}</strong></div></div>`;
    });
    
    html += `</div><div style="display:flex;justify-content:space-between;align-items:center;margin-top:40px"><button onclick="prevSlide()" style="padding:10px 20px;background:#FF8A3C;color:white;border:none;border-radius:6px;cursor:pointer;font-weight:600">← Prev</button><span id="slide-counter" style="color:rgba(255,255,255,0.6)">1 / 13</span><button onclick="nextSlide()" style="padding:10px 20px;background:#FF8A3C;color:white;border:none;border-radius:6px;cursor:pointer;font-weight:600">Next →</button></div></div></div><script>let currentSlide=0;const slides=document.querySelectorAll('.slide');function showSlide(n){slides.forEach(s=>s.style.display='none');if(slides[n])slides[n].style.display='block';document.getElementById('slide-counter').innerText=(n+1)+' / '+slides.length}function nextSlide(){currentSlide=(currentSlide+1)%slides.length;showSlide(currentSlide)}function prevSlide(){currentSlide=(currentSlide-1+slides.length)%slides.length;showSlide(currentSlide)}showSlide(0);document.addEventListener('keydown',e=>{if(e.key==='ArrowRight')nextSlide();if(e.key==='ArrowLeft')prevSlide()})</script>`;
    
    res.setHeader('Content-Type', 'text/html; charset=utf-8');
    res.send(html);
  } catch (err) {
    res.status(500).send('<div style="color:#c33;padding:20px">Error: ' + err.message + '</div>');
  }
});

